"use client"

import Link from "next/link"
import { usePathname } from "next/navigation"
import { Package, Users, Calculator, ClipboardList, ChevronLeft, ChevronRight, LayoutDashboard } from "lucide-react"
import { cn } from "@/lib/utils"
import { useIsMobile } from "@/hooks/use-mobile" // Asegurate de que la ruta sea correcta

interface SidebarProps {
  collapsed: boolean
  onToggleCollapse: () => void
  stats: {
    totalRolls: number
    totalClients: number
    activeOrders: number
  }
}

const NAV_ITEMS = [
  { href: "/gestion/inventario", label: "Inventario", icon: Package },
  { href: "/gestion/clientes", label: "Clientes", icon: Users },
  { href: "/gestion/calculadora", label: "Calculadora de Corte", icon: Calculator },
  { href: "/gestion/ordenes", label: "Ordenes", icon: ClipboardList },
]

export default function Sidebar({ collapsed, onToggleCollapse, stats }: SidebarProps) {
  const pathname = usePathname()
  const isMobile = useIsMobile()

  // 1. VISTA MÓVIL: BOTÓN VOLVER (Cuando ya entramos a una sección)
  // Si estamos en /gestion/inventario, etc., el sidebar "desaparece" y queda este botón
  if (isMobile && pathname !== "/gestion") {
    return (
      <div className="fixed top-0 left-0 w-full z-50 bg-[#0e0e0e]/90 backdrop-blur-md border-b border-[#2a2520] px-4 py-3 flex items-center justify-between">
        <Link 
          href="/gestion" 
          className="flex items-center gap-2 text-[#c9a961] font-medium"
        >
          <ChevronLeft size={20} />
          <span>Volver al Menú</span>
        </Link>
        <span className="text-[#6b6560] text-xs uppercase tracking-widest font-serif">
          Amarigom
        </span>
      </div>
    )
  }

  // 2. VISTA ESCRITORIO O MENÚ PRINCIPAL MÓVIL
  return (
    <aside
      className={cn(
        "flex flex-col bg-[#0e0e0e] border-[#2a2520] transition-all duration-300",
        isMobile 
          ? "w-full min-h-screen p-6" // En S9 el menú ocupa toda la pantalla
          : cn("sticky top-0 h-screen border-r", collapsed ? "w-[72px]" : "w-[260px]")
      )}
    >
      {/* Logo y Header */}
      <div className={cn(
        "flex items-center gap-3 border-[#2a2520]",
        isMobile ? "mb-10" : "px-5 py-6 border-b"
      )}>
        <div className="flex items-center justify-center w-10 h-10 rounded-lg bg-[#c9a961] text-[#0a0a0a] flex-shrink-0">
          <span className="font-serif text-xl font-bold">A</span>
        </div>
        {(!collapsed || isMobile) && (
          <div>
            <h1 className="font-serif text-lg text-[#c9a961] tracking-wider uppercase">AMARIGOM</h1>
            <p className="text-[10px] text-[#6b6560] tracking-[0.2em] uppercase">Gestión Interna</p>
          </div>
        )}
      </div>

      {/* Navegación */}
      <nav className={cn(
        "flex-1 flex flex-col gap-2",
        isMobile ? "py-4" : "px-3 py-4"
      )}>
        {NAV_ITEMS.map(({ href, label, icon: Icon }) => {
          const isActive = pathname === href
          return (
            <Link
              key={href}
              href={href}
              className={cn(
                "flex items-center transition-all duration-200 w-full",
                isMobile 
                  ? "gap-5 px-6 py-5 rounded-2xl bg-[#1a1a1a] border border-[#2a2520] text-lg" // Botones gigantes para el celu
                  : "gap-3 px-3 py-2.5 rounded-lg text-sm",
                isActive && !isMobile
                  ? "bg-[#c9a961]/10 text-[#c9a961] border-[#c9a961]/20"
                  : "text-[#a0998c] hover:text-[#f5f0e8]"
              )}
            >
              <Icon size={isMobile ? 24 : 18} className="text-[#c9a961]" />
              {(!collapsed || isMobile) && <span>{label}</span>}
              {isMobile && <ChevronRight size={18} className="ml-auto opacity-30" />}
            </Link>
          )
        })}
      </nav>

      {/* Estadísticas (Solo en Desktop no colapsado o siempre en Móvil) */}
      {(!collapsed || isMobile) && (
        <div className={cn("border-t border-[#2a2520]", isMobile ? "py-8" : "px-4 py-4")}>
          <div className="flex flex-col gap-3">
             <p className="text-[10px] text-[#6b6560] uppercase tracking-widest mb-1">Estado del Stock</p>
            <div className="flex justify-between items-center text-sm lg:text-xs">
              <span className="text-[#a0998c]">Total Rollos</span>
              <span className="font-medium text-[#f5f0e8]">{stats.totalRolls}</span>
            </div>
            <div className="flex justify-between items-center text-sm lg:text-xs">
              <span className="text-[#a0998c]">Clientes Activos</span>
              <span className="font-medium text-[#f5f0e8]">{stats.totalClients}</span>
            </div>
          </div>
        </div>
      )}

      {/* Botón Colapsar (Solo Desktop) */}
      {!isMobile && (
        <button
          onClick={onToggleCollapse}
          className="flex items-center justify-center py-4 border-t border-[#2a2520] text-[#6b6560] hover:text-[#c9a961]"
        >
          {collapsed ? <ChevronRight size={18} /> : <ChevronLeft size={18} />}
        </button>
      )}
    </aside>
  )
}